import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import './App.css';

// ── Change this to your PC's local IP if testing from mobile
// Example: http://192.168.1.45:8080/api/students
const API_BASE = 'http://localhost:8080/api/students';

const EMPTY_FORM = { name: '', subject: '', mark: '' };

function App() {
  const [students, setStudents]     = useState([]);
  const [form, setForm]             = useState(EMPTY_FORM);
  const [editingId, setEditingId]   = useState(null);
  const [loading, setLoading]       = useState(false);
  const [toast, setToast]           = useState(null);  // { msg, type }
  const [log, setLog]               = useState([]);    // thread activity log

  // ── Fetch all students ──────────────────────────────
  const fetchStudents = useCallback(async () => {
    try {
      const { data } = await axios.get(API_BASE);
      setStudents(data);
    } catch {
      showToast('Could not connect to backend. Is Spring Boot running?', 'error');
    }
  }, []);

  useEffect(() => { fetchStudents(); }, [fetchStudents]);

  // Auto-refresh every 3 seconds so thread effects are visible
  useEffect(() => {
    const interval = setInterval(fetchStudents, 3000);
    return () => clearInterval(interval);
  }, [fetchStudents]);

  // ── Toast helper ────────────────────────────────────
  const showToast = (msg, type = 'success') => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 4000);
  };

  const addLog = (entry) => {
    setLog(prev => [{ time: new Date().toLocaleTimeString(), entry }, ...prev.slice(0, 49)]);
  };

  // ── Form handlers ───────────────────────────────────
  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const resetForm = () => { setForm(EMPTY_FORM); setEditingId(null); };

  // ── CRUD ─────────────────────────────────────────────
  const handleSubmit = async () => {
    if (!form.name || !form.subject || !form.mark) {
      showToast('Please fill in all fields.', 'error'); return;
    }
    setLoading(true);
    try {
      const payload = { ...form, mark: parseFloat(form.mark) };
      if (editingId) {
        await axios.put(`${API_BASE}/${editingId}`, payload);
        showToast('Student updated successfully.');
        addLog(`Updated student "${form.name}" (ID ${editingId})`);
      } else {
        await axios.post(API_BASE, payload);
        showToast('Student added successfully.');
        addLog(`Added student "${form.name}" with mark ${form.mark}`);
      }
      resetForm();
      fetchStudents();
    } catch {
      showToast('Error saving student.', 'error');
    }
    setLoading(false);
  };

  const handleEdit = (s) => {
    setForm({ name: s.name, subject: s.subject, mark: s.mark });
    setEditingId(s.id);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDelete = async (id, name) => {
    if (!window.confirm(`Delete "${name}"?`)) return;
    try {
      await axios.delete(`${API_BASE}/${id}`);
      showToast(`"${name}" deleted.`);
      addLog(`Manually deleted student "${name}" (ID ${id})`);
      fetchStudents();
    } catch {
      showToast('Error deleting student.', 'error');
    }
  };

  // ── THREAT 1 ─────────────────────────────────────────
  const handleThreat1 = async () => {
    if (!form.name || !form.subject || !form.mark) {
      showToast('Fill in student details to activate Threat 1.', 'error'); return;
    }
    setLoading(true);
    try {
      const payload = { ...form, mark: parseFloat(form.mark) };
      const { data } = await axios.post(`${API_BASE}/threat1`, payload);
      showToast(`⚠️ Threat 1 activated! ID ${data.insertedId} will be deleted in 2s.`, 'threat1');
      addLog(`[THREAT-1] Inserted "${form.name}" (ID ${data.insertedId}) — will auto-delete in 2s`);
      resetForm();
      fetchStudents();
    } catch {
      showToast('Could not activate Threat 1.', 'error');
    }
    setLoading(false);
  };

  // ── THREAT 2 ─────────────────────────────────────────
  const handleThreat2 = async () => {
    if (!form.name || !form.subject || !form.mark) {
      showToast('Fill in student details to activate Threat 2.', 'error'); return;
    }
    setLoading(true);
    try {
      const payload = { ...form, mark: parseFloat(form.mark) };
      const { data } = await axios.post(`${API_BASE}/threat2`, payload);
      showToast(`⚠️ Threat 2 activated! Mark ${data.originalMark} will be halved in 2s.`, 'threat2');
      addLog(`[THREAT-2] Inserted "${form.name}" mark=${data.originalMark} — will be halved in 2s`);
      resetForm();
      fetchStudents();
    } catch {
      showToast('Could not activate Threat 2.', 'error');
    }
    setLoading(false);
  };

  // ── Grade helper ─────────────────────────────────────
  const getGrade = (mark) => {
    if (mark >= 90) return { label: 'A+', cls: 'grade-a-plus' };
    if (mark >= 80) return { label: 'A',  cls: 'grade-a' };
    if (mark >= 70) return { label: 'B',  cls: 'grade-b' };
    if (mark >= 60) return { label: 'C',  cls: 'grade-c' };
    if (mark >= 50) return { label: 'D',  cls: 'grade-d' };
    return { label: 'F', cls: 'grade-f' };
  };

  // ── Render ────────────────────────────────────────────
  return (
    <div className="app">

      {/* Toast notification */}
      {toast && (
        <div className={`toast toast-${toast.type}`}>
          {toast.msg}
        </div>
      )}

      {/* Header */}
      <header className="header">
        <div className="header-inner">
          <div className="header-title">
            <span className="header-icon">🎓</span>
            <div>
              <h1>Student Mark System</h1>
              <p>React · Spring Boot · MySQL</p>
            </div>
          </div>
          <div className="header-stats">
            <div className="stat-box">
              <span className="stat-num">{students.length}</span>
              <span className="stat-lbl">Records</span>
            </div>
            <div className="stat-box">
              <span className="stat-num">
                {students.length > 0
                  ? (students.reduce((s, x) => s + x.mark, 0) / students.length).toFixed(1)
                  : '—'}
              </span>
              <span className="stat-lbl">Avg Mark</span>
            </div>
          </div>
        </div>
      </header>

      <main className="main">

        {/* ── Form Card ── */}
        <div className="card">
          <div className="card-title">
            {editingId ? `✏️ Edit Student (ID: ${editingId})` : '➕ Add Student'}
          </div>

          <div className="form-grid">
            <div className="form-group">
              <label>Student Name</label>
              <input name="name" value={form.name} onChange={handleChange} placeholder="e.g. Arjun Kumar" />
            </div>
            <div className="form-group">
              <label>Subject</label>
              <input name="subject" value={form.subject} onChange={handleChange} placeholder="e.g. Mathematics" />
            </div>
            <div className="form-group">
              <label>Mark (0 – 100)</label>
              <input name="mark" type="number" min="0" max="100" value={form.mark} onChange={handleChange} placeholder="e.g. 85" />
            </div>
          </div>

          <div className="btn-row">
            <button className="btn btn-primary" onClick={handleSubmit} disabled={loading}>
              {editingId ? 'Update' : 'Add Student'}
            </button>
            {editingId && (
              <button className="btn btn-outline" onClick={resetForm}>Cancel</button>
            )}
          </div>

          {/* Threat buttons */}
          <div className="threat-section">
            <div className="threat-label">⚡ Thread Simulation (fill form first)</div>
            <div className="btn-row">
              <button className="btn btn-threat1" onClick={handleThreat1} disabled={loading}>
                🧵 Threat 1 — Insert &amp; Auto-Delete
              </button>
              <button className="btn btn-threat2" onClick={handleThreat2} disabled={loading}>
                🧵 Threat 2 — Insert &amp; Manipulate Mark
              </button>
            </div>
            <p className="threat-note">
              Both threats insert the record first, then a background Java thread runs after 2 seconds.
              Watch the table refresh automatically to see the effect.
            </p>
          </div>
        </div>

        {/* ── Table Card ── */}
        <div className="card">
          <div className="card-title-row">
            <span className="card-title">📋 Student Records</span>
            <button className="btn btn-sm btn-outline" onClick={fetchStudents}>↻ Refresh</button>
          </div>

          {students.length === 0 ? (
            <div className="empty-state">No records found. Add a student above.</div>
          ) : (
            <div className="table-wrap">
              <table>
                <thead>
                  <tr>
                    <th>ID</th>
                    <th>Name</th>
                    <th>Subject</th>
                    <th>Mark</th>
                    <th>Grade</th>
                    <th>Created At</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {students.map(s => {
                    const grade = getGrade(s.mark);
                    return (
                      <tr key={s.id}>
                        <td className="td-id">#{s.id}</td>
                        <td className="td-name">{s.name}</td>
                        <td>{s.subject}</td>
                        <td className="td-mark">{s.mark}</td>
                        <td><span className={`grade-badge ${grade.cls}`}>{grade.label}</span></td>
                        <td className="td-date">
                          {s.createdAt ? new Date(s.createdAt).toLocaleString() : '—'}
                        </td>
                        <td>
                          <div className="action-row">
                            <button className="btn btn-sm btn-edit" onClick={() => handleEdit(s)}>Edit</button>
                            <button className="btn btn-sm btn-delete" onClick={() => handleDelete(s.id, s.name)}>Delete</button>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>

        {/* ── Thread Activity Log ── */}
        <div className="card">
          <div className="card-title">🪵 Thread Activity Log</div>
          {log.length === 0 ? (
            <div className="empty-state">No thread activity yet. Trigger a threat to see logs here.</div>
          ) : (
            <div className="log-list">
              {log.map((l, i) => (
                <div key={i} className={`log-entry ${l.entry.includes('THREAT-1') ? 'log-t1' : l.entry.includes('THREAT-2') ? 'log-t2' : ''}`}>
                  <span className="log-time">{l.time}</span>
                  <span className="log-msg">{l.entry}</span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* ── Mobile Trigger Guide ── */}
        <div className="card card-info">
          <div className="card-title">📱 Trigger from Mobile</div>
          <p>Make sure your phone is on the same WiFi as your PC. Replace <code>localhost</code> with your PC's local IP.</p>
          <div className="code-block">
            <div className="code-line"><span className="code-method post">POST</span> http://YOUR_PC_IP:8080/api/students/threat1</div>
            <div className="code-line"><span className="code-method post">POST</span> http://YOUR_PC_IP:8080/api/students/threat2</div>
            <div className="code-body">
              {`Body (JSON):\n{\n  "name": "Test Student",\n  "subject": "Maths",\n  "mark": 85\n}`}
            </div>
          </div>
          <p style={{ marginTop: 10, fontSize: 13, color: 'var(--gray)' }}>
            Use <strong>Postman</strong> (free mobile app) to send requests from your phone.
            Find your PC IP: run <code>ipconfig</code> (Windows) or <code>ifconfig</code> (Mac/Linux).
          </p>
        </div>

      </main>
    </div>
  );
}

export default App;
